const defaults = $('Load Global Settings').first()?.json ?? {};
const request = $('Send No-Address Emails Webhook').first()?.json ?? $input.first()?.json ?? {};
const query = request.query ?? {};
const params = request.params ?? {};
const candidates = [
  request.batch_id,
  request.batchId,
  query.batch_id,
  query.batchId,
  query.batch,
  params.batch_id,
  params.batchId,
];
const rawBatchId = candidates.find((value) => value !== undefined && value !== null && String(value).trim() !== '');
const parsedBatchId = rawBatchId === undefined ? null : Number.parseInt(String(rawBatchId), 10);
const modeCandidates = [
  request.delivery_mode,
  request.deliveryMode,
  query.delivery_mode,
  query.deliveryMode,
  query.mode,
  params.delivery_mode,
  params.deliveryMode,
  defaults.default_delivery_mode,
];
const normalizedMode = String(modeCandidates.find((value) => value !== undefined && value !== null && String(value).trim() !== '') ?? 'test').trim().toLowerCase();
const deliveryMode = normalizedMode === 'production' ? 'production' : 'test';
const recipientCandidates = [
  request.test_recipient,
  request.testRecipient,
  query.test_recipient,
  query.testRecipient,
  params.test_recipient,
  params.testRecipient,
  defaults.default_test_recipient,
];
const rawTestRecipient = recipientCandidates.find((value) => value !== undefined && value !== null && String(value).trim() !== '');
const testRecipient = String(rawTestRecipient ?? 'steve.short@gmail.com').trim();
const overrideCandidates = [
  request.override,
  request.override_send,
  request.force_send,
  request.force,
  query.override,
  query.override_send,
  query.force_send,
  query.force,
  params.override,
  params.override_send,
  params.force_send,
  params.force,
];
const rawOverride = overrideCandidates.find((value) => value !== undefined && value !== null && String(value).trim() !== '');
const normalizedOverride = String(rawOverride ?? '').trim().toLowerCase();
const overrideSend = ['1', 'true', 'yes', 'y', 'on'].includes(normalizedOverride);
return [{
  json: {
    batch_id: Number.isInteger(parsedBatchId) && parsedBatchId > 0 ? parsedBatchId : null,
    template_key: defaults.no_address_email_template_key || 'shoe_tag_pigeon_hole',
    signature_template_key: defaults.email_signature_template_key || 'signature',
    sender_name: defaults.email_sender_name || 'Steve Short',
    reply_to: defaults.email_reply_to || 'members.avondaleltc@gmail.com',
    delivery_mode: deliveryMode,
    test_recipient: testRecipient,
    override_send: overrideSend,
  }
}];

const config = $input.first()?.json ?? {};
const batchId = config.batch_id;
if (batchId === null) {
  return [{ json: { sql: "SELECT 'batch_id is required' AS error_message, 400 AS response_code, NULL::boolean AS no_address_email_sent;" } }];
}
const overrideSend = config.override_send ? 'TRUE' : 'FALSE';
const isTestMode = config.delivery_mode !== 'production' ? 'TRUE' : 'FALSE';
return [{
  json: {
    sql: `SELECT
      CASE
        WHEN b.id IS NULL THEN 'Batch ${batchId} does not exist'
        WHEN b.no_address_email_sent AND NOT ${overrideSend} THEN 'No-address emails have already been sent for batch ${batchId}'
        WHEN COALESCE(b.status, '') <> 'Complete' AND NOT ${isTestMode} THEN 'Batch ${batchId} is ' || COALESCE(NULLIF(b.status, ''), 'Unknown') || ' and production no-address emails can only be sent when Complete'
        ELSE NULL
      END AS error_message,
      CASE
        WHEN b.id IS NULL THEN 404
        WHEN b.no_address_email_sent AND NOT ${overrideSend} THEN 409
        WHEN COALESCE(b.status, '') <> 'Complete' AND NOT ${isTestMode} THEN 409
        ELSE 200
      END AS response_code,
      COALESCE(b.no_address_email_sent, false) AS no_address_email_sent
    FROM (SELECT 1) AS stub
    LEFT JOIN public.signup_batches b ON b.id = ${batchId};`,
  }
}];

const rawRecipients = $input.all().map((item) => item.json ?? {});
const recipients = rawRecipients.filter((recipient) => {
  if (!recipient || typeof recipient !== 'object') return false;
  return [recipient.payer, recipient.email_address, recipient.first_name, recipient.last_name]
    .some((value) => value !== undefined && value !== null && String(value).trim() !== '');
});
const config = $('Resolve Batch Id').first().json;
const validation = $('Validate Batch').first()?.json ?? {};
return [{
  json: {
    batch_id: config.batch_id,
    recipient_count: recipients.length,
    recipients,
    template_key: config.template_key,
    signature_template_key: config.signature_template_key || 'signature',
    sender_name: config.sender_name,
    reply_to: config.reply_to,
    delivery_mode: config.delivery_mode,
    test_recipient: config.test_recipient,
    override_send: Boolean(config.override_send),
    no_address_email_sent: Boolean(validation.no_address_email_sent),
  }
}];

const item = $('Collect Recipient Data').first().json;
const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
const sql = `with main_template as (
  select template_key, subject_template, text_template, html_template
  from public.email_templates
  where template_key = ${sqlLiteral(item.template_key)}
    and is_active = true
  order by id desc
  limit 1
), signature_template as (
  select template_key, subject_template, text_template, html_template
  from public.email_templates
  where template_key = ${sqlLiteral(item.signature_template_key || 'signature')}
    and is_active = true
  order by id desc
  limit 1
)
select
  main_template.template_key,
  main_template.subject_template,
  main_template.text_template,
  main_template.html_template,
  signature_template.template_key as signature_template_key,
  signature_template.text_template as signature_text_template,
  signature_template.html_template as signature_html_template
from main_template
left join signature_template on true;`;
return [{ json: { batch_id: item.batch_id, sql } }];

const summary = $('Collect Recipient Data').first().json;
const template = $('Load Email Template').first()?.json ?? {};
if (!template.template_key) {
  throw new Error(`Email template ${summary.template_key} was not found`);
}
const splitName = (payer) => {
  const trimmed = String(payer ?? '').trim();
  if (!trimmed) return { first_name: '', last_name: '' };
  const parts = trimmed.split(/\s+/);
  return {
    first_name: parts[0] ?? '',
    last_name: parts.slice(1).join(' '),
  };
};
const applyTokens = (value, recipient) => {
  const fallbackName = splitName(recipient.payer);
  const firstName = String(recipient.first_name ?? '').trim() || fallbackName.first_name;
  const lastName = String(recipient.last_name ?? '').trim() || fallbackName.last_name;
  const emailAddress = String(recipient.email_address ?? '').trim();
  const tokenMap = {
    '{{$json.first_name}}': firstName,
    '{{$json.last_name}}': lastName,
    '{{$json.email_address}}': emailAddress,
    '{{$json.address_1}}': recipient.address_1 ?? '',
    '{{$json.address_2}}': recipient.address_2 ?? '',
    '{{$json.town}}': recipient.town ?? '',
    '{{$json.postcode}}': recipient.postcode ?? '',
    '{{$json.contact.first_name}}': firstName,
    '{{$json.contact.last_name}}': lastName,
    '{{$json.contact.email_address}}': emailAddress,
    '{{$json.contact.address_1}}': recipient.address_1 ?? '',
    '{{$json.contact.address_2}}': recipient.address_2 ?? '',
    '{{$json.contact.town}}': recipient.town ?? '',
    '{{$json.contact.postcode}}': recipient.postcode ?? '',
    '{{$json.member.first_name}}': firstName,
    '{{$json.member.last_name}}': lastName,
    '{{$json.member.email_address}}': emailAddress,
    '{{first_name}}': firstName,
    '{{last_name}}': lastName,
    '{{email_address}}': emailAddress,
    '{{address_1}}': recipient.address_1 ?? '',
    '{{address_2}}': recipient.address_2 ?? '',
    '{{town}}': recipient.town ?? '',
    '{{postcode}}': recipient.postcode ?? '',
    '<first name>': firstName,
    '<last name>': lastName,
    '<email address>': emailAddress,
    '{contact.first_name}': firstName,
    '{contact.last_name}': lastName,
    '{contact.email_address}': emailAddress,
    '{contact.address_1}': recipient.address_1 ?? '',
    '{contact.address_2}': recipient.address_2 ?? '',
    '{contact.town}': recipient.town ?? '',
    '{contact.postcode}': recipient.postcode ?? '',
    '{member.first_name}': firstName,
    '{member.last_name}': lastName,
    '{member.email_address}': emailAddress,
  };
  let rendered = String(value ?? '');
  for (const [token, replacement] of Object.entries(tokenMap)) {
    rendered = rendered.split(token).join(String(replacement));
  }
  return rendered.trim();
};
const emailType = template.html_template && !template.text_template ? 'html' : 'text';
const bodySource = emailType === 'html'
  ? (template.html_template ?? template.text_template ?? '')
  : (template.text_template ?? template.html_template ?? '');
const signatureSource = emailType === 'html'
  ? (template.signature_html_template ?? template.signature_text_template ?? '')
  : (template.signature_text_template ?? template.signature_html_template ?? '');
const joinSeparator = emailType === 'html' ? '<br><br>' : '\n\n';
return summary.recipients.map((recipient) => {
  const fallbackName = splitName(recipient.payer);
  const firstName = String(recipient.first_name ?? '').trim() || fallbackName.first_name;
  const lastName = String(recipient.last_name ?? '').trim() || fallbackName.last_name;
  const originalEmail = String(recipient.email_address ?? '').trim();
  const isTestMode = summary.delivery_mode !== 'production';
  const targetEmail = isTestMode ? summary.test_recipient : originalEmail;
  const renderedMessage = applyTokens(bodySource, { ...recipient, first_name: firstName, last_name: lastName, email_address: originalEmail });
  const renderedSignature = applyTokens(signatureSource, { ...recipient, first_name: firstName, last_name: lastName, email_address: originalEmail });
  const composedMessage = [renderedMessage, renderedSignature].filter(Boolean).join(joinSeparator).trim();
  const finalMessage = isTestMode
    ? `${composedMessage}\n\n---\nTEST MODE\nOriginal recipient: ${originalEmail}\nPayer: ${recipient.payer}`
    : composedMessage;
  return {
    json: {
      batch_id: summary.batch_id,
      to_email: targetEmail,
      original_to_email: originalEmail,
      payer: recipient.payer,
      sender_name: summary.sender_name,
      reply_to: summary.reply_to,
      template_key: template.template_key,
      signature_template_key: template.signature_template_key || summary.signature_template_key || 'signature',
      delivery_mode: summary.delivery_mode,
      test_recipient: summary.test_recipient,
      rendered_subject: applyTokens(template.subject_template ?? 'Message from Avondale about your tags', { ...recipient, first_name: firstName, last_name: lastName, email_address: originalEmail }),
      rendered_message: finalMessage,
      email_type: emailType,
      recipient_first_name: firstName,
      recipient_last_name: lastName,
    }
  };
});

const summary = $('Collect Recipient Data').first().json;
const shouldMarkSent = summary.delivery_mode === 'production';
const sql = shouldMarkSent
  ? `UPDATE public.signup_batches SET no_address_email_sent = true WHERE id = ${summary.batch_id};`
  : 'SELECT false AS no_address_email_sent_updated;';
return [{
  json: {
    batch_id: summary.batch_id,
    should_mark_sent: shouldMarkSent,
    sql,
  }
}];

const sentItems = $('Send Gmail Message').all();
const summary = $('Collect Recipient Data').first().json;
const shouldMarkSent = $('Build Mark Sent SQL').first()?.json?.should_mark_sent === true;
return [{
  json: {
    message: `Sent ${sentItems.length} email(s) for batch ${summary.batch_id} in ${summary.delivery_mode} mode`,
    batch_id: summary.batch_id,
    delivery_mode: summary.delivery_mode,
    test_recipient: summary.test_recipient,
    override_send: Boolean(summary.override_send),
    no_address_email_sent: shouldMarkSent ? true : Boolean(summary.no_address_email_sent),
    sent_count: sentItems.length,
    recipients: sentItems.map((item) => ({
      payer: item.json.payer,
      email: item.json.to_email,
      original_email: item.json.original_to_email,
      first_name: item.json.recipient_first_name,
      last_name: item.json.recipient_last_name,
    })),
  }
}];
